const body = $json.body ?? {};
const canonical = JSON.stringify({
  topic: String(body.topic ?? '').trim(),
  audience: String(body.audience ?? 'tech professionals').trim(),
  tone: String(body.tone ?? 'educational and inspiring').trim(),
  language: String(body.language ?? 'English').trim(),
});
return [{ json: { ...body, canonical } }];

const results = $json.results || [];
const researchText = results.map((r, i) => `[${i+1}] ${r.title}\n${r.content}\nSource: ${r.url}`).join('\n\n');
return [{ json: { ...$('Setup Context').item.json, researchText } }];

