const raw = $json.choices?.[0]?.message?.content;
if (!raw) throw new Error('Missing AI response');
return [{ json: { ...$('Normalize Research').item.json, script: JSON.parse(raw) } }];

const raw = $json.choices?.[0]?.message?.content;
if (!raw) throw new Error('Scene Planner returned no content');
const parsed = JSON.parse(raw);
if (!Array.isArray(parsed.scenes) || parsed.scenes.length === 0) throw new Error('Scene Planner returned no valid scenes');
const scenes = parsed.scenes.map((scene, index) => ({ ...scene, scene_index: index + 1, scene_id: `scene-${String(index + 1).padStart(3, '0')}` }));
return [{ json: { ...$('Parse + Validate Script').item.json, scenes } }];

let scenesArray = $json.scene_index.map((index, i) => ({
  scene_index: index, scene_id: $json.scene_id[i], narration: $json.narration[i], visual_prompt: $json.visual_prompt[i], duration_seconds: $json.duration_seconds[i],
  asset_url: `${$env.SUPABASE_ASSET_BASE_URL || $env.SUPABASE_PROJECT_URL + '/storage/v1/object/public/' + $env.SUPABASE_BUCKET_NAME}/jobs/${$('Setup Context').item.json.job_id}/scenes/${$json.scene_id[i]}.png`
}));
scenesArray.sort((a, b) => a.scene_index - b.scene_index);
return [{ json: { scenes: scenesArray } }];

const raw = $json.choices?.[0]?.message?.content;
if (!raw) throw new Error('Missing SEO response');
const parsed = JSON.parse(raw);
let title = $('Setup Context').item.json.topic.substring(0, 95);
let description = (parsed.description || '').substring(0, 4900);
let tags = Array.isArray(parsed.tags) ? parsed.tags.slice(0, 15) : [];
return [{ json: { seo: { title, description, tags } } }];

const m = $json;
if (!m.thumb_url || !m.voice_url || !m.scenes || !m.seo) throw new Error('Manifest incomplete');
const source = {
  output_format: 'mp4',
  elements: [
    { type: 'audio', track: 1, source: m.voice_url, duration: 'media' },
    ...m.scenes.map((s, i) => ({
      type: 'image', track: 2, time: i === 0 ? 0 : 'previous_end', duration: s.duration_seconds, source: s.asset_url, dynamic_content: true
    }))
  ]
};
return [{ json: { ...m, render_source: source } }];

const h = $json.headers || {};
const url = h.location || h.Location || h.LOCATION;
if (!url) throw new Error('Missing Location header from YT');
return [{ json: { yt_upload_url: url } }];
